<style lang="scss" scoped>
.comp-cycle {
  display: flex;
  .label {
    margin-right: 10px;
  }
  .cycle-input {
    margin-right: 10px;
    width: 160px;
  }
}
</style>
<template>
  <div class="comp-cycle">
    <span class="label">每</span>
    <el-input
      v-model="cycle"
      :class="cycleClass"
      type="text"
      clearable
      placeholder="請輸入結算區間數"
      @change="onChange"
    />
    <el-select v-model="unit" clearable placeholder="請選擇" @change="onChange">
      <el-option
        v-for="item in units"
        :key="item.value"
        size="mini"
        :label="item.label"
        :value="item.value"
      />
    </el-select>
  </div>
</template>

<script>
export default {
  name: 'SettlementCycle',
  props: ['value'],
  data() {
    const { cycle = '', unit = '' } = this.value
    return {
      units: [
        { label: '天', value: 'day' },
        { label: '周', value: 'week' },
        { label: '月', value: 'month' }
      ],
      cycle,
      unit
    }
  },
  computed: {
    // cycle-input
    cycleClass() {
      const { cycle } = this
      return [
        'cycle-input',
        {
          'is-error': !cycle
        }
      ]
    }
  },
  watch: {
    value(newVal, oldVal) {
      const { cycle = '', unit = '' } = newVal
      this.cycle = cycle
      this.unit = unit
    }
  },
  created() {},
  methods: {
    onChange(e) {
      this.$emit('input', {
        cycle: this.cycle,
        unit: this.unit
      })
    }
  }
}
</script>
